import React, { useState } from 'react';
import { getTasks, useQuery } from 'wasp/client/operations';
import { createTask, triggerJob } from 'wasp/client/operations';

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const [description, setDescription] = useState('');

  const handleCreateTask = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!description) return;
    try {
      await createTask({ description });
      setDescription('');
    } catch (err: any) {
      window.alert('Error: ' + err.message);
    }
  };

  const handleTriggerJob = async () => {
    try {
      await triggerJob();
      window.alert('Background job triggered!');
    } catch (err: any) {
      window.alert('Error: ' + err.message);
    }
  };

  return (
    <main className="container" style={{ padding: '2rem' }}>
      <h2>Background Jobs</h2>

      <form onSubmit={handleCreateTask}>
        <input 
          type="text" 
          value={description} 
          onChange={e => setDescription(e.target.value)} 
          placeholder="Task description" 
        />
        <button type="submit">Create Task</button>
      </form>

      <div style={{ marginTop: '1rem' }}>
        <button onClick={handleTriggerJob}>Trigger Background Job</button>
      </div>

      <div style={{ marginTop: '2rem' }}>
        {isLoading && <p>Loading tasks...</p>}
        {error && <p>Error loading tasks.</p>}
        {tasks && (
          <ul>
            {tasks.map(task => (
              <li key={task.id}>
                {task.description} - {task.isProcessed ? 'Processed' : 'Unprocessed'}
              </li>
            ))}
          </ul>
        )}
      </div>
    </main>
  );
}

